query:
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`, createdAt, updatedAt) SELECT id, 26, 'Müşteri ihtiyaçlarını anlar ve bu ihtiyaçları doğru şekilde tanımlar.', 1, NOW(), NOW() FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık';
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`, createdAt, updatedAt) SELECT id, 27, 'Müşteri sorunlarına hızlı ve etkili çözümler bulur.', 2, NOW(), NOW() FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık';
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`, createdAt, updatedAt) SELECT id, 28, 'Müşterisine karşı anlayışlı, sabırlı ve saygılı bir iletişim tarzı benimser.', 3, NOW(), NOW() FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık';
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`, createdAt, updatedAt) SELECT id, 29, 'Müşteri memnuniyeti artırmaya yönelik çalışmalara katkıda bulunur. ', 4, NOW(), NOW() FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık';
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`, createdAt, updatedAt) SELECT id, 31, 'Yaptığı işin sonuçlarının kurumun beklediği ticari sonuçlar ile paralel olmasını gözetir.', 1, NOW(), NOW() FROM position_categories WHERE positionId = 8 AND name = 'Ticari Bakış';
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`, createdAt, updatedAt) SELECT id, 32, 'Uygun durumlarda, satış fırsatlarını geliştirecek alternatif yaklaşımlar tavsiye eder.        ', 2, NOW(), NOW() FROM position_categories WHERE positionId = 8 AND name = 'Ticari Bakış';
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`, createdAt, updatedAt) SELECT id, 33, 'Kurumun müşteri sayısını geliştirmeye yönelik çalışmalarda bulunur.', 3, NOW(), NOW() FROM position_categories WHERE positionId = 8 AND name = 'Ticari Bakış';
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`, createdAt, updatedAt) SELECT id, 35, 'Görevlerini sahip olduğu zamanı dikkate alarak gereken sürede tamamlar.', 1, NOW(), NOW() FROM position_categories WHERE positionId = 8 AND name = 'Planlama ve Organize Etme';
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`, createdAt, updatedAt) SELECT id, 36, 'Birden fazla işe odaklanarak bunları eş zamanlı yürütebilir. ', 2, NOW(), NOW() FROM position_categories WHERE positionId = 8 AND name = 'Planlama ve Organize Etme';
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`, createdAt, updatedAt) SELECT id, 37, 'Planlama ile ilgili öncelikleri saptar, yetki sınırları içinde doğru sıralamayı gerçekleştirir.', 3, NOW(), NOW() FROM position_categories WHERE positionId = 8 AND name = 'Planlama ve Organize Etme';

